  ('cpa-moex-00121', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法就外國公司之規定，下列敘述，何者正確？', '["外國公司應在我國境內指定其依證券交易法之訴訟及非訴訟代理人各一人", "外國公司指定之代理人，應在我國境內有住所或居所", "外國公司指定之代理人，應經主管機關核准", "已依證券交易法相關規定辦理之外國公司，如於我國境內設立分公司或營業，無須再依公司法 規定辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00122', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法之規定，公開發行公司最遲應於每會計年度第一季、第二季及第三季終了後幾日內， 公告並申報經會計師核閱及提報董事會之財務報告？', '["15日內", "1個月內", "45日內", "2個月內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00123', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法第36條公告申報之合併財務報告，下列何種情形應重編財務報告並重行公告？', '["更正資產負債表個別項目（不含重分類，下略）金額在新臺幣（下同）3千萬元以上", "更正資產負債表個別項目金額在1千萬元以上", "更正資產負債表個別項目金額在3千萬元以上，且達原決算總資產金額3%者", "更正資產負債表個別項目金額在1千萬元以上，且達原決算總資產金額1%者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00124', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法之規定，A公開發行公司（下稱A公司）之董事、監察人或經理人，意圖為自己或 第三人之利益，而為違背其職務之行為或侵占公司資產，致 A 公司遭受損害達新臺幣多少金額 者，處3年以上10年以下有期徒刑，得併科新臺幣1千萬元以上2億元以下罰金？', '["1百萬元", "2百萬元", "3百萬元", "5百萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00125', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '會計師甲為其客戶A上市公司（下稱A公司）辦理財務報告查核簽證業務，過程中因過失未發現 A公司財務報告之重大疏漏，主管機關得知後擬對甲為處分。主管機關的處分手段不包括下列何者？', '["對甲為警告", "停止甲辦理簽證業務2年", "勒令甲服務之事務所停業6個月", "撤銷對甲簽證之核准"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00126', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為一家從事通訊傳播的上市公司。甲為拉抬A公司股價，與乙約定，在甲出售A公司股票 時，乙同時為購買之行為，則甲乙二人之行為可能構成下列何種操縱行為？', '["沖洗買賣", "違約不交割", "相對委託", "短線交易"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00127', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為A公開發行公司（下稱A公司）之董事。由於甲利用職務之便，讓A公司為不合營業常規 且不利益之交易，導致公司遭受重大損害。依證券交易法之規定，下列敘述，何者錯誤？', '["甲可依法處3年以上10年以下有期徒刑，得併科新臺幣1千萬元以上2億元以下罰金", "若甲因犯罪獲取之財物或財產上利益金額達新臺幣1億元以上者，處7年以上有期徒刑，得併 科新臺幣2千5百萬元以上5億元以下罰金", "若甲利用職務之便，使A公司為不合營業常規且不利益之交易之行為係屬於無償行為，則A公 司得聲請法院撤銷該行為", "若甲利用職務之便，使A公司為不合營業常規且不利益之交易之行為係屬於有償行為，受益人 於受益時不知其情事者，基於保護公司利益，A公司亦得聲請法院撤銷該行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00128', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計法規定，關於公司組織主辦會計之任免，下列敘述，何者正確？', '["若為股份有限公司，應由股東會以股東之過半數之出席，及出席股東過半數之同意", "若為有限公司，應有全體股東過半數之同意", "若為無限公司，應有全體股東之同意", "若為兩合公司，應有全體無限責任股東之同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00129', 'cpa', 'cpa-moex-113-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計處理準則規定，下列那些會計項目可能同時出現於短期性及長期性投資？①避險之金', '["按攤銷後成本衡量之金融資產", "採用權益法之投資", "透過損益按公允價值衡量 之金融資產  ⑤以成本衡量之金融資產", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:59+00:00", "source_pdf_sha1": "de36fb7a9031", "answer_pdf_sha1": "369b73c92d99", "source_family": "moex-gov-tw", "moex": {"exam_code": "113130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "113", "exam_name": "113年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
